"""
mkt-original | zechariah | ch8–11, 13 (ch12 already written; ch14 also done)
run: python3 scripts/zc-original-zechariah-8-13.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ZECHARIAH = {
  "8": {
    "1": "<p>Standard prophetic reception formula: <em>vayyehi davar YHWH tzevaot</em> (the word of YHWH of hosts came). The double name <em>YHWH tzevaot</em> (LORD of armies) appears 18x in chs 7-8, underscoring the divine warrior-ruler who controls the nations.</p>",
    "2": "<p><em>qin'ah gedolah</em> (great jealousy/zeal) from root <em>qana'</em>. The same root covers both jealousy (emotional exclusivity) and zeal (passionate action for a cause). The marital overtone is native to covenant language: YHWH's <em>qin'ah</em> for Zion reflects the exclusive loyalty of a husband, making unfaithfulness intolerable. The doubled construction <em>qin'ah gedolah qinne'ti lah</em> intensifies: YHWH is burning with jealous zeal on Zion's behalf, not merely feeling it.</p>",
    "3": "<p><em>shakhanti b'qerev Yerushalayim</em> (I will dwell in the midst of Jerusalem). Root <em>shakan</em> (to dwell, tabernacle) is the source of <em>Shekinah</em>; its announcement here reverses the programmatic departure of YHWH's glory in Ezek 10-11. Jerusalem renamed <em>ir ha-'emet</em> (city of faithfulness/truth) and <em>har qodesh</em> (the holy mountain) — titles pointing to covenantal rather than merely geographic identity.</p>",
    "4": "<p><em>zaqenim v'zeqenot</em> (old men and old women) sitting in the streets — the image of normalcy restored. Old age living peacefully in public is a sign of civic security; in ancient cities, violence drove elders indoors. <em>mish'enet</em> (staff) in hand signals both frailty and longevity — both honored in the new Jerusalem.</p>",
    "5": "<p><em>rechovot ha-'ir</em> (the plazas/broad streets of the city) filled with <em>yeladim viyladot</em> (boys and girls). <em>mesahakim</em> (playing) from root <em>sachaq</em> = laughter, play. Children playing publicly signal the absence of warfare and famine. The vision deliberately pairs old age (v4) with childhood (v5) as the two most vulnerable groups — both flourishing marks complete shalom.</p>",
    "6": "<p><em>nifle't</em> (marvelous, surpassingly difficult) from root <em>pala'</em> = to be extraordinary, beyond normal capacity. <em>b'eynei she'erit ha-am</em> (in the eyes of the remnant of this people) — the rhetorical question challenges the people's unbelief: 'Is anything too wonderful for YHWH of hosts?' The same root underlies Ps 118:23 (marvelous in our eyes) and Jer 32:17, 27 (nothing too difficult for YHWH).</p>",
    "7": "<p><em>yoshiv</em> Hiphil from <em>yashav</em> (to sit, dwell) = cause to dwell. <em>moshia'</em> (savior, deliverer) — same root as <em>yeshua'</em>. The ingathering from <em>'eretz mizrach</em> (land of the east) and <em>eretz mevo' ha-shemesh</em> (land of the setting sun = west) anticipates a universal return surpassing the Babylonian-era return from one direction.</p>",
    "8": "<p><em>v'hayu li l'am va'ani ehyeh lahem l'Elohim b'emet ub'tsedaqah</em> (they will be my people and I will be their God in faithfulness and in righteousness). The covenant formula first stated at Sinai (Exod 6:7; Lev 26:12) now carries the double qualifier <em>'emet</em> (faithfulness, truth, reliability) and <em>tsedaqah</em> (righteousness). The addition signals that the renewed covenant will be established on a qualitatively different footing than the old.</p>",
    "9": "<p><em>yad chazaq</em> (let your hands be strong) — imperative addressed to those hearing the prophets' words in the day of the temple's foundation (Ezra 3/Zech 1). The historical grounding ties eschatological promise to present obedience. The contrast with the pre-restoration period (v10) emphasizes the turning-point nature of the temple rebuilding.</p>",
    "10": "<p><em>sakar ha-adam lo nihyah</em> (wages of man did not materialize) — before those days no productive work was safe or profitable. <em>shachar</em> (adversary/enemy) sent every man against his neighbor. The economic and social disruption is the covenant-curse pattern (Deut 28:33; Lev 26:16) now being reversed in the era of restoration.</p>",
    "11": "<p><em>zera' ha-shalom</em> (seed of peace) — an agricultural image for YHWH's sowing. The vine, earth, and heavens will each yield: the reversal of the covenant-curse on the land (Deut 28:23-24; Hag 1:10-11). <em>natan</em> (will give/bestow) three times — land, heavens, dew — all yield when YHWH restores covenant fellowship.</p>",
    "12": "<p><em>nachalatam</em> (their inheritance/possession) — the remnant will inherit all these good things. Same root <em>nachal</em> as the land-grant terminology in the Pentateuch. <em>al-tira'u</em> (do not be afraid) — the comfort formula of Isaiah 40-55's servant songs appropriated for the restoration community.</p>",
    "13": "<p><em>qillalah hayitem baggoyim</em> (you were a curse among the nations) — the reversal of the Abrahamic <em>meqallelekhah</em> curse (Gen 12:3). YHWH now declares: <em>v'hoshia'ti 'ethem viheyitem berakah</em> (I will save you and you will be a blessing). The Abrahamic commission to be a blessing to nations, disrupted by exile, is here reinstated. The same covenant arc undergirds Gal 3:13-14: the curse absorbed by Christ yields the blessing flowing to nations.</p>",
    "14": "<p><em>ka'asher zamam-ti</em> (just as I purposed) to bring disaster when your ancestors provoked me... <em>v'lo nichamti</em> (I did not relent). Divine purpose is constant — the same sovereign will that brought judgment now purposes restoration. The symmetry of vv14-15 is programmatic: covenant judgment and covenant blessing flow from the same unchanging divine will.</p>",
    "15": "<p><em>shavti zamam-ti</em> (I have returned and purposed) to do good to Jerusalem and to Judah. The Hiphil of <em>shuv</em> + <em>zamam</em> mirrors v14's identical construction of divine purpose reversed: as YHWH purposed (<em>zamam</em>) evil, he has now re-purposed to do good. The repetition is deliberate structural symmetry.</p>",
    "16": "<p><em>'emet dibberu ish et re'ehu</em> (speak truth each man to his neighbor); <em>mishpat 'emet v'shalom shiphtu bisheareykem</em> (judge with true and peaceful judgment in your gates). Gate justice (<em>sha'ar</em>) is the locus of ancient Israelite legal proceedings; the call to <em>'emet</em> (truth) in both speech and courts echoes Amos 5:15 and Isa 1:17. Ethical imperatives flow from eschatological promises — restored community requires truthful social fabric.</p>",
    "17": "<p><em>ra'at re'ekhem al-tachshavu bilvavkhem</em> (do not devise evil against your neighbor in your heart). <em>sheva' shaqer</em> (false oath) — <em>shava'</em> (to swear) invoked falsely; the third commandment's social application. <em>eleh sane'ti</em> (these I hate) — strong covenantal language of divine displeasure echoing Amos 5:21 and Prov 6:16-19.</p>",
    "18": "<p>The four historical fasts — <em>tsomot</em> (fasts) of the fourth month (Tammuz, fall of Jerusalem's walls, 2 Kgs 25:3), fifth month (Av, temple destruction, Jer 52:12), seventh month (Tishri, murder of Gedaliah, Jer 41), and tenth month (Tevet, beginning of the siege, 2 Kgs 25:1) — each commemorated a stage of the 586 BCE catastrophe. Together they structured the liturgical year as a calendar of grief.</p>",
    "19": "<p><em>l'sason ul'simchah ul'mo'adim tovim</em> (joy and gladness and cheerful festivals) — the four mourning-fasts transformed into four feasts. The mourning-to-joy reversal is paradigmatic for the whole restoration: exile's grief becomes restoration's feast. <em>'emet v'ha-shalom 'ehavu</em> (love truth and peace) closes the unit as ethical summary after eschatological promise.</p>",
    "20": "<p><em>od asher yavo'u ammim v'yoshvey 'arim rabbot</em> (yet will come peoples and inhabitants of many cities). The universal pilgrimage vision now opens beyond the immediate restoration community. <em>'od</em> (still, again, yet) marks continuation and escalation — there is more to come than the initial return from Babylon.</p>",
    "21": "<p><em>n'lecha halokh l'chalot et pnei YHWH</em> (let us go to entreat the face of YHWH) — <em>chalah panim</em> (to soften/entreat the face) is technical prayer language used of approaching the king through supplication (Exod 32:11; 1 Kgs 13:6). The chain of invitation — each city calling to the next — pictures spontaneous Gentile pilgrimage rather than commanded obligation.</p>",
    "22": "<p><em>amim rabbim v'goyim 'atsumim</em> (many peoples and mighty/numerous nations) streaming to seek YHWH of hosts in Jerusalem. <em>l'vaqesh</em> (to seek) — the deliberate, effortful seeking of the divine presence; the same verb Amos uses for seeking YHWH rather than Bethel (Amos 5:4-6). The eschatological pilgrimage fulfills the Abrahamic promise (Gen 12:3) and Isa 2:2-4.</p>",
    "23": "<p><em>asarah anashim miqqol leshonot ha-goyim</em> (ten men from all the languages of the nations). Ten = representative fullness. <em>v'hecheziku biknaf ish Yehudi</em> (they will seize the edge/wing of a Jewish man's garment) — <em>kanaf</em> (wing, hem, edge) is the corner of the outer garment; to grasp it is to claim connection and blessing (cf. Ruth 3:9). <em>ki shama'nu Elohim 'immakem</em> (we have heard that God is with you) — <em>Elohim 'immakem</em> (God is with you) is the Immanuel formula universalized.</p>"
  },
  "9": {
    "1": "<p><em>massa' devar YHWH</em> (the burden/oracle of the word of YHWH) — the same superscription opens ch12 and Mal 1:1. <em>massa'</em> (burden, oracle) carries the double meaning of a heavy load and a prophetic lifting-up of the voice; the LXX renders it <em>lēmma</em> (that which is received). <em>Chadrakh</em> — the Assyrian district <em>Ḫatarikka</em> north of Syria; the oracle sweeps the Syro-Phoenician corridor southward toward Israel.</p>",
    "2": "<p><em>v'gam Chamat tighbal bah</em> (even Hamath which borders on it). The geographic sweep — Hadrach, Damascus, Hamath, Tyre, Sidon — traces the Phoenician-Syrian corridor. <em>Tzor v'Tsidon ki chakhmah me'od</em> (Tyre and Sidon, though very wise) — their legendary commercial wisdom (Ezek 28) will not protect them from the divine warrior.</p>",
    "3": "<p><em>vativen Tzor matsod lah</em> (Tyre built herself a fortress/mound). The verb plays on <em>Tsor</em> (Tyre = rock/fortress). <em>vatitsbar keseph ke'afar</em> (she heaped up silver like dust) — Tyre's legendary wealth (Ezek 27); <em>charutz</em> (fine gold) like street-mud. The accumulation is about to be reversed.</p>",
    "4": "<p><em>hinne YHWH yorashenah</em> (behold YHWH will dispossess her). <em>yarash</em> Hiphil = to cause to be dispossessed. <em>v'hikkah ba-yam cheilah</em> (he will strike her rampart/wealth into the sea). <em>chayil</em> (wealth, army, force) consumed by fire (<em>ba-'esh tukhal</em>); fulfilled historically in Alexander's 332 BCE destruction of island Tyre by causeway.</p>",
    "5": "<p><em>tir'eh Ashqelon v'tira</em> (Ashkelon will see and be afraid). The Philistine cities witness Tyre's fall and panic. <em>v'lo yeshev melekh ba-Azzah</em> (no king will remain in Gaza) — loss of royal dynasty signals political collapse. The Philistine pentapolis is systematically dismantled as part of the same divine-warrior campaign.</p>",
    "6": "<p><em>veyashav mamzer b'Ashdod</em> (a bastard/half-breed will inhabit Ashdod). <em>mamzer</em> (bastard, of mixed/forbidden birth, Deut 23:2) signals ethnic dissolution — Ashdod's pure lineage replaced by a mixed community, ending its identity as a distinct nation. <em>v'hikhratti ga'on Pelishthim</em> (I will cut off the pride of the Philistines) — <em>ga'on</em> (pride) is typically the object of divine judgment.</p>",
    "7": "<p><em>va'hasiroti damav mipihu</em> (I will remove his blood from his mouth) — the bloody sacrificial practices of the Philistines removed. <em>shiqqutsav</em> (his detestable things/abominations) from between his teeth. Remarkably, the Philistine remnant is absorbed into YHWH's people like the <em>Yevusi</em> (Jebusite) in Jerusalem — indigenous peoples who became Israelites (2 Sam 24:16-25). The enemy becomes the covenant community.</p>",
    "8": "<p><em>v'chaniti l'veiti missava</em> (I will encamp around my house as a garrison). <em>chanah</em> (to encamp) is military language — YHWH as divine army camping around the temple-house. <em>v'lo ya'avor 'alehem od noges</em> (no taskmaster/oppressor will pass over them again) — <em>noges</em> = taskmaster (Exod 3:7; 5:6), the exodus vocabulary repristinated for the new era.</p>",
    "9": "<p>The climactic verse. <em>gili me'od bat Tsiyon</em> (rejoice greatly O daughter of Zion). <em>hinne malkechi yavo lakh</em> (your king comes to you) — the king arrives as gift to the city, not as conqueror. Four descriptors: (1) <em>tsaddiq</em> (righteous) — the Davidic king who embodies covenant justice; (2) <em>nosha'</em> (saved/victorious) — Niphal passive, 'one who is saved' by YHWH rather than by military might; (3) <em>'ani</em> (humble, poor, afflicted) — applied also to Moses (Num 12:3) and the suffering servant; (4) <em>rokev al chamor v'al 'ayir ben 'atonot</em> (riding on a donkey, on a colt the foal of a she-donkey). The Hebrew parallelism is synonymous — one animal described twice; Matthew 21:5 reads the parallelism as two animals, reflecting his literal-fulfillment exegetical method.</p>",
    "10": "<p><em>v'hikhratti rekev me'Ephraim v'sus miYrushalayim</em> (I will cut off the chariot from Ephraim and the horse from Jerusalem). The king's arrival on a donkey enacts disarmament: chariot, horse, and <em>qeshet milchamah</em> (battle bow) — the complete military apparatus — are removed. <em>v'dibber shalom laggoyim</em> (he will speak/proclaim peace to the nations). The dominion formula from Ps 72:8 follows: from sea to sea, from the River to the ends of the earth.</p>",
    "11": "<p><em>gam 'at b'dam briteki</em> (as for you also, by the blood of your covenant). <em>dam brit</em> (blood of the covenant) — the technical term for covenant inauguration through sacrifice; specifically the Sinai covenant of Exod 24:8 where Moses sprinkled blood and declared 'this is the blood of the covenant.' <em>shilachchti asirayikh mibbor ein mayim bo</em> (I have released your prisoners from the pit with no water in it) — waterless cistern as imprisonment-image (cf. Joseph in Gen 37:24; Jer 38:6).</p>",
    "12": "<p><em>shuvu l'vitsaron asirey ha-tiqvah</em> (return to the stronghold, O prisoners of hope). <em>bitsaron</em> (stronghold, fortress) as metaphorical refuge. <em>asirey ha-tiqvah</em> (prisoners of hope) = those whose only security is future hope, not present circumstances — a description of the exilic community. <em>mishneh ashiv lakh</em> (I will restore double to you) — <em>mishneh</em> (double) echoes Isa 40:2 and 61:7 where Israel receives double restitution for her shame.</p>",
    "13": "<p><em>ki darakhti lakh Yehudah qeshet</em> (for I drew Judah as my bow). YHWH as divine warrior uses Judah as his bow and Ephraim as the arrow — the people as divine weapons. <em>ve'orarthi vanayikh Tsiyon 'al vanayikh Yavan</em> (I will rouse your sons O Zion against your sons O Greece/Iavan) — <em>Yavan</em> (Iavan, Javan = Greece) appears rarely in prophetic oracles; this verse is among the clearest references to Greece as an eschatological opponent.</p>",
    "14": "<p><em>vaYHWH 'aleyhem yera'eh</em> (YHWH will appear over them) — the divine warrior-king appearing in battle. <em>v'yatsa' ka-baraq chittso</em> (his arrow will go out like lightning) — theophanic combat imagery (Ps 144:6). <em>v'YHWH Elohim beshofar yitqa'</em> (YHWH God will blow the shofar) — the shofar announces both battle and divine kingship (Ps 47:5; Exod 19:16).</p>",
    "15": "<p><em>YHWH tzevaot yaggen 'aleyhem</em> (YHWH of hosts will protect/shield them). <em>v'akhlu v'khaveshu avne qela'</em> (they will devour and tread down the sling-stones) — defeating the weapons hurled against them. The victory imagery is deliberately excessive, emphasizing divine empowerment of a people otherwise outnumbered.</p>",
    "16": "<p><em>v'hoshia'am YHWH Eloheihem b'yom hahu</em> (YHWH their God will save them on that day). <em>k'tson ammo</em> (like the flock of his people) — the shepherd-flock metaphor returns. <em>avnei nezer mitnos'sot 'al admato</em> (the stones of a diadem/crown will glitter over his land) — the people as precious jewels in YHWH's crown, displayed over the land.</p>",
    "17": "<p><em>ki mah tuvah u-mah yaphuthu</em> (for how good and how beautiful) — exclamation of wonder at the restoration. <em>dagan yaphiyach bachurim v'tirosh yenovev betulot</em> (grain will make young men flourish and new wine the young women). <em>tirosh</em> (new wine) and <em>dagan</em> (grain) are the emblems of covenant blessing (Deut 11:14; Hos 2:8). The restoration benefits the next generation — the inverse of the covenant-curse where children suffered.</p>"
  },
  "10": {
    "1": "<p><em>sha'alu meYHWH matar</em> (ask rain from YHWH). The appeal to YHWH for rain stands in deliberate contrast to the teraphim and diviners of v2. <em>b'et malqosh</em> (in the season of the latter rain) — the <em>malqosh</em> (spring rain, March-April) was critical for grain maturation; Deut 11:14 lists it as a covenant blessing. <em>YHWH 'oseh chazizim</em> (YHWH who makes the storm-clouds) — he controls the weather that the Baals falsely claimed to govern.</p>",
    "2": "<p><em>ki ha-teraphim dibberu 'aven</em> (for the teraphim spoke vanity/wickedness). <em>teraphim</em> = household cult-figurines used for divination; prohibited by the Mosaic law on <em>kosem</em> (divination). <em>v'ha-qosmim chazah shaqer</em> (the diviners see falsehood/lies). <em>va-yenachu ka-tson</em> (they wandered like sheep) — the sheep-wandering image prefigures the shepherd-critique of vv3-5; without a true shepherd the flock wanders into false guidance.</p>",
    "3": "<p><em>'al ha-ro'im charah 'appi</em> (my anger is hot against the shepherds). <em>ro'im</em> (shepherds) = political/religious leaders; <em>'attudim</em> (male goats) = the strong leaders of the flock, equally culpable. <em>paqad YHWH tzevaot et 'edro</em> (YHWH of hosts has attended to/visited his flock) — <em>paqad</em> (to visit, attend to, appoint) is the key term of both judgment and rescue (Exod 3:16; 4:31); here YHWH visits the flock to save it while judging the shepherds.</p>",
    "4": "<p><em>mimmennu pinna</em> (from him the cornerstone) — <em>pinna</em> (corner, cornerstone) is the load-bearing foundation stone; the Davidic Messiah as architectural foundation echoes Ps 118:22 and Isa 28:16. Three more leadership metaphors from the same source: <em>mimmennu yated</em> (from him the tent peg) = the structural pin that holds the whole together (Isa 22:23-25); <em>mimmennu qeshet milchamah</em> (from him the battle bow); <em>yetse' kol noges yachdav</em> (from him every ruler together). All four derive from a single Messianic figure as source of all legitimate authority.</p>",
    "5": "<p><em>v'hayu kagibbor-im bosim b'tiyt chutsot b'milchamah</em> (they will be like warriors treading in the mud of the streets in battle). The restored people fight with divine empowerment. <em>v'nilchamu ki YHWH 'imam</em> (they will fight because YHWH is with them) — the decisive factor is divine presence, not human capacity; the divine-warrior formula (Deut 20:4; Josh 10:14).</p>",
    "6": "<p><em>v'gibbareti et beit Yehudah v'et beit Yosef oshia'</em> (I will strengthen the house of Judah and save the house of Joseph). The reunification of Judah (south) and Joseph/Ephraim (north) is the eschatological horizon of Ezek 37:15-28 (the two sticks). <em>v'hayu ka'asher lo zelachtim</em> (they will be as though I had not cast them off) — the exile treated as if it never happened, a complete restorative reversal.</p>",
    "7": "<p><em>v'hayu k'gibbor Ephraim</em> (Ephraim will be like a warrior) — the northern tribe, long scattered, restored to military identity. <em>v'samach libbam baYHWH</em> (their heart will rejoice in YHWH) — joy rooted in YHWH, not in military victory. <em>u-veneyhem yir'u v'samchu</em> (their children will see and rejoice) — the restoration extends to the next generation, contrasting with the covenant-curse (Exod 20:5).</p>",
    "8": "<p><em>eshreqa lahem v'aqabetsem</em> (I will whistle/signal for them and gather them). <em>sharaq</em> (to whistle, hiss) is how a shepherd signals the flock; also how YHWH calls distant nations as instruments (Isa 5:26; 7:18). <em>ki paditi otam</em> (for I redeemed them) — <em>padah</em> (to redeem by payment, ransom) is exodus-redemption vocabulary repristinated for the new ingathering.</p>",
    "9": "<p><em>va'azra'em ba'ammim</em> (I will scatter them among the peoples) — the scattering understood as YHWH's purposive act, not merely exile. <em>uv'merchaqqim yizk'runi</em> (in far places they will remember me) — even in dispersion, the memory of YHWH is preserved; the scattering serves a missiological purpose. <em>v'chayu im-beneyhem v'shavu</em> (they and their children will live and return) — the promise encompasses both the scattered and their diaspora-born children.</p>",
    "10": "<p><em>v'hashivotim me'eretz Mitsraim</em> (I will bring them back from Egypt) and <em>me'Ashur aqabetsem</em> (from Assyria I will gather them). Egypt and Assyria are the two historic poles of Israel's enslavement — the second-Exodus pattern. <em>v'el eretz Gil'ad ul'Levanon aviyem</em> (to the land of Gilead and Lebanon I will bring them) — Gilead (Transjordan) and Lebanon (northern boundary) = the full territorial extent of the promised land.</p>",
    "11": "<p><em>v'avar b'yam tsarah</em> (he will pass through the sea of distress). The Exodus sea-crossing pattern inverted: YHWH himself passes through the sea, striking its waves. <em>v'hikkah b'yam gallim</em> (he will strike the waves of the sea) — the divine warrior smiting the chaotic waters (Ps 89:9-10; Isa 51:9-10). <em>v'hovishu kol metsulot ye'or</em> (all the depths of the Nile will dry up) — echoing the plague pattern (Exod 7:17-21) and Isa 11:15.</p>",
    "12": "<p><em>v'gibbartim baYHWH</em> (I will strengthen them in YHWH) — not in military might. <em>uv'shemo yithalaku</em> (in his name they will walk/go about) — <em>halakh b'shem</em> (to walk in the name of) is covenant-loyalty language; Mic 4:5 uses the same phrase for ongoing devotion. The chapter closes by returning to YHWH as source of both strength and direction.</p>"
  },
  "11": {
    "1": "<p><em>p'tach Levanon deleticha</em> (open your doors O Lebanon) — ironic imperative addressed to Lebanon as if opening for a conqueror. Lebanon's famous cedars (<em>arazim</em>) are the target of judgment-fire. In OT symbolism, Lebanon's cedars represent the proud and powerful (Isa 2:13; 10:34). The passage may also allude to the Temple — built from Lebanese cedar — as a way of signaling temple-destruction is in view.</p>",
    "2": "<p><em>helil berosh</em> (wail O cypress) for the cedar has fallen; the <em>'abbir</em> (mighty ones) are ruined. The cascade of mourning from Lebanon's cedars to the oaks of Bashan pictures the collapse of all proud structures. <em>ya'ar ha-vatir</em> (impenetrable forest) — the mighty forest laid bare.</p>",
    "3": "<p><em>qol yelalat ha-ro'im</em> (sound of the wailing of the shepherds). The shepherds wail because their <em>addaretam</em> (glory, splendor) is ruined. <em>qol sha'agat kepharim</em> (sound of roaring young lions) — the pride of the Jordan's thicket, where lions dwelt (Jer 49:19; 50:44), mourning the destruction of their habitat. Shepherds and lions both face the same catastrophe.</p>",
    "4": "<p><em>ro'eh et tson ha-haregah</em> (shepherd the flock of slaughter) — the prophet is commanded to act out the role of shepherd over a doomed flock. <em>asher qonehem yaharg-um v'lo ye'ashmu</em> (whose buyers slaughter them without guilt) — the buyers (foreign powers, exploitative leaders) kill with impunity. <em>u'mokherey-hem yomeru barukh YHWH</em> (their sellers say 'Blessed be the LORD') — cynical enrichment from the flock's exploitation, cloaked in piety.</p>",
    "5": "<p><em>v'lo yachmolu ro'eyhem</em> (their shepherds do not spare them). The triple indictment — buyer, seller, shepherd — forms a complete system of exploitation with no internal advocate. The flock has no recourse within its own leadership structure; YHWH alone intervenes by sending his shepherd-prophet.</p>",
    "6": "<p><em>ki lo achmal 'od 'al yoshvey ha-aretz</em> (for I will no longer spare the inhabitants of the land). <em>nachal</em> (deliver, hand over) — 'each man I will hand into his neighbor's hand and into the hand of his king.' <em>v'pittsu 'et ha-aretz v'lo atssil miyyyadam</em> (they will devastate the land and I will not rescue from their hand) — divine abandonment to self-destructive violence, the covenant-curse pattern of Deut 28:48-57.</p>",
    "7": "<p><em>va'er'eh et tson ha-haregah</em> (I shepherded the flock of slaughter). Two staffs: <em>no'am</em> (pleasantness, favor, grace) — representing YHWH's covenant-goodness toward the people; <em>chovelim</em> (cords, binders) — representing the bond uniting Judah and Israel. The staffs are functioning governance symbols; their breaking (vv10, 14) enacts the dissolution of covenant relationship.</p>",
    "8": "<p><em>va'akhched et shloshet ha-ro'im b'yerach echad</em> (I destroyed three shepherds in one month). The identity of the three shepherds is the most debated puzzle in Zechariah — proposed candidates range from Zerubbabel/Joshua/Sheshbazzar to specific Seleucid kings. The point is symbolic completeness: three represents a full set of condemned leaders. <em>va'tiqtsar naphshi bam</em> (my soul grew impatient/weary of them) — the shepherd-prophet's exhaustion mirrors divine frustration with the leadership.</p>",
    "9": "<p><em>lo er'eh ethem</em> (I will not shepherd you) — the shepherd abandons the incorrigible flock. The three-part formula of abandonment: what is dying let it die; what is being destroyed let it be destroyed; the remaining will devour each other's flesh. Progressive intensification ending in social cannibalism echoes the severest covenant-curse of Deut 28:53-57.</p>",
    "10": "<p><em>v'eqach et maq-li 'et no'am</em> (I took my staff, Pleasantness) and broke it to annul my covenant with all peoples (<em>l'hapheyr et beriti asher karoti et kol ha-ammim</em>). The staff-breaking is a covenant-dissolution ceremony. The broken <em>no'am</em> staff represents the end of YHWH's protective covenant that had prevented the nations from harming Israel (Ezek 34:25-31).</p>",
    "11": "<p><em>va-tupar bayyom hahu</em> (it was annulled on that day). <em>v'yide'u ken 'aniyyey ha-tson ha-shomrim 'oti</em> (the afflicted/poor of the flock who were watching me knew that it was the word of YHWH). The <em>'aniyyim</em> (poor, afflicted) recognize the prophetic-divine act — the remnant theology: the humble receive the word that the powerful miss.</p>",
    "12": "<p><em>'im tov b'einekhem havu sakhari</em> (if it is good in your eyes give me my wages). The wages-request frames the evaluation of the shepherd's worth. <em>va-yishqelu et sakhari sheloshim keseph</em> (they weighed out my wages: thirty pieces of silver). Thirty silver pieces = the compensation for a gored slave (Exod 21:32) — the legal indemnity for the lowest-status person. The Piel <em>shaqal</em> (to weigh out silver) is the commercial term for payment before coined money.</p>",
    "13": "<p><em>v'yo'mer YHWH 'elai hashlikhehu el ha-yotser</em> (YHWH said to me 'throw it to the potter'). The thirty pieces are returned to the temple treasury (<em>beit YHWH</em>) and given to the potter (<em>yotser</em>). <em>'addir ha-yaqar asher yaqarti me'aleyhem</em> (the magnificent price at which I was valued by them) — <em>yaqar</em> normally means precious/costly; the sarcasm is biting: this 'lordly price' is slave-compensation. Matthew 27:3-10 cites this passage as fulfilled in Judas's thirty silver pieces returned to the temple and used to buy the potter's field.</p>",
    "14": "<p><em>v'ashbor et maq-li ha-sheni et ha-chovelim</em> (I broke my second staff, the Cords/Binders). The breaking represents the dissolution of fraternal unity between Judah and Israel. <em>l'hapheyr et ha-'achavah bein Yehudah u-vein Yisra'el</em> (to break the brotherhood between Judah and Israel). The allegory reaches its nadir: covenant with the nations broken (v10), internal union of God's people dissolved (v14).</p>",
    "15": "<p><em>od qach-lekha keli ro'eh 'ewiliy</em> (take again the implements of a foolish/worthless shepherd). The second prophetic role is now enacted — the prophet must embody the <em>ro'eh ha-'ewili</em> (foolish shepherd) as a warning against what is coming. <em>'ewiliy</em> (foolish) in Proverbs connotes moral obtuseness, not merely intellectual failure.</p>",
    "16": "<p><em>ki hinne 'anokhi meqim ro'eh ba-aretz</em> (for behold I am raising up a shepherd in the land). The worthless shepherd's four failures: (1) does not attend to the perishing (<em>lo yiphqod 'et ha-nikhadhot</em>); (2) does not seek the scattered (<em>ha-na'ar lo yevaqesh</em>); (3) does not heal the broken (<em>v'ha-nishberet lo yirape'</em>); (4) does not nourish the healthy (<em>ha-nitstsebet lo yekhalkel</em>). Four pastoral failures defining the anti-shepherd — the inverse of the Good Shepherd of Ezek 34:16.</p>",
    "17": "<p><em>hoy ro'i ha-'elil</em> (woe to the worthless/idol shepherd who abandons the flock). <em>'elil</em> (worthless, of no account, idol) — the same word used for idols in Isa 2:8; here applied to the false shepherd as a deliberate anti-type to the divine shepherd. <em>cherev 'al zero'o v'al 'eyn yemino</em> (a sword on his arm and on his right eye). The arm (<em>zero'a</em>) represents strength; the right eye represents insight/leadership capacity. Both are permanently destroyed: <em>zero'o yavosh tiyyavesh v'eyn yemino kaho tikheh</em> (his arm will be completely withered and his right eye utterly blinded).</p>"
  },
  "13": {
    "1": "<p><em>b'yom hahu yihyeh maqor niftach l'veit David ul'yoshevey Yerushalayim</em> (on that day a fountain will be opened for the house of David and for the inhabitants of Jerusalem). <em>maqor</em> (fountain, spring) — flowing water as purification source. The purpose: <em>l'chata't ul'niddah</em> (for sin and for impurity/ceremonial uncleanness). <em>chata't</em> = sin/sin-offering; <em>niddah</em> = menstrual impurity/bodily uncleanness. The pairing covers both moral guilt and ritual defilement — the fountain cleanses comprehensively. Passive <em>niftach</em> (will be opened) emphasizes divine action: YHWH opens what humans cannot access themselves.</p>",
    "2": "<p><em>akhrit 'et shemot ha-'atsavim min ha-aretz</em> (I will cut off the names of the idols from the land). <em>'atsavim</em> (idols, images) — from root <em>'atsav</em> (grief, pain); idols cause grief. Their <em>names</em> being cut off means their identity is obliterated. <em>v'et ha-nevi'im v'et ruch ha-tum'ah</em> (and the prophets and the spirit of uncleanness) — false prophecy linked to impure spirits (1 Kgs 22:22-23; Ezek 13) will be purged alongside idolatry.</p>",
    "3": "<p><em>v'hayah ki yinnave' ish 'od</em> (if a man prophesies again). Parents will pierce their own child who prophesies falsely — reflecting Deut 13:6-10 (requiring death even for a close relative who leads to apostasy). <em>davar shaqer dibbarta b'shem YHWH</em> (you have spoken falsehood in the name of YHWH) — the criterion is false prophecy in YHWH's name, which Mosaic law makes a capital offense (Deut 18:20).</p>",
    "4": "<p><em>vayhi bayyom hahu yevoshu ha-nevi'im</em> (on that day the prophets will be ashamed). In the purified community, prophets hide their identity. <em>'aderet se'ar</em> (garment of hair, hairy mantle) — the distinctive outer garment of the prophet; Elijah's mantle (1 Kgs 19:13; 2 Kgs 1:8) was its paradigmatic form. False prophets had used the hairy costume to claim prophetic authority; in the new era the costume itself becomes incriminating.</p>",
    "5": "<p><em>ki 'eved 'adamah 'anokhi</em> (for I am a man who works the soil). The exposed prophet denies his vocation: <em>lo navi' anokhi</em> (I am not a prophet) — inverting Amos's self-description (Amos 7:14: 'I am not a prophet, nor a prophet's son'). Amos denied the professional prophetic guild to affirm his divine call; the Zechariah figure denies prophecy altogether to avoid death.</p>",
    "6": "<p><em>mah ha-makkot ha-'elleh bein yadeicha</em> (what are these wounds/blows between your hands?). <em>makkot</em> (blows, wounds, stripes) — same root as the plagues of Egypt. <em>bein yadeicha</em> (between your hands) could mean wrists or torso. The question reveals cult lacerations — self-inflicted wounds of Baal prophets (1 Kgs 18:28). He deflects: <em>asher hukkeyti beit me'ahavai</em> (I was struck in the house of my friends/lovers) — an ambiguous denial that can be read as both evasion and deeper prophetic truth pointing beyond itself.</p>",
    "7": "<p><em>herev uri al ro'i v'al gever 'amiti</em> (O sword, awake against my shepherd and against the man who is my associate). <em>ro'i</em> (my shepherd) — YHWH's own shepherd. <em>'amiti</em> (my associate, my fellow, the man close to me) — <em>'amiti</em> appears in Leviticus for 'neighbor' or 'fellow-citizen' (Lev 18:20; 19:11-18); applied here to YHWH's own companion, a title of remarkable intimacy for a human figure. <em>hak et ha-ro'eh uteputseynah ha-tson</em> (strike the shepherd and the sheep will be scattered) — Jesus quotes this in Gethsemane (Matt 26:31; Mark 14:27), applying it to his betrayal and the disciples' flight. <em>v'hashivoti yadi 'al ha-tze'irim</em> (I will turn my hand against the little ones) — YHWH's hand turned against his own flock as part of the purifying judgment.</p>",
    "8": "<p><em>v'hayah b'khol ha-aretz</em> (it will happen in all the land). The arithmetic of judgment: <em>shenayim chalakim yikkareitu yamutu</em> (two-thirds will be cut off and die); <em>ha-shelishit yivvater bah</em> (one-third will be left in it). The survival ratio echoes Ezek 5:1-4's three-way division of Jerusalem's population. Two-thirds perishing is covenant-curse severity; one-third preserved is the remnant theology.</p>",
    "9": "<p><em>v'heveti et ha-shelishit ba'esh</em> (I will bring the one-third through fire). Two metallurgical verbs: <em>tsarafti otam kitstseraph et ha-keseph</em> (I will refine them as silver is refined) and <em>u-vecharti otam kivchar et ha-zahav</em> (I will test them as gold is tested). <em>tsaraf</em> (to smelt, refine) and <em>bachan</em> (to test, assay) — the purification process that removes dross (Ps 12:6; Prov 17:3; Isa 48:10). The refining leads to covenant renewal: <em>'ammi hu v'hu yomar YHWH Elohai</em> (he is my people, and he will say 'YHWH is my God') — the covenant formula in its fullest mutual form.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'zechariah')
    merge_comm(existing, ZECHARIAH)
    save_comm('mkt-original', 'zechariah', existing)
    print('Zechariah 8-11, 13 original written.')

if __name__ == '__main__':
    main()
